// ── OData $filter parser (basic eq and substringof support) ─────────────────

function parseFilter(filterStr) {
    if (!filterStr) return null;
    // Split on " and " to get individual conditions
    const conditions = filterStr.split(/\s+and\s+/i);
    const filters = [];
    for (const cond of conditions) {
        // Match: Field eq 'Value'
        let m = cond.match(/(\w+)\s+eq\s+'([^']+)'/);
        if (m) { filters.push({ field: m[1], op: "eq", value: m[2] }); continue; }
        // Match: Field eq Value (unquoted — for decimals)
        m = cond.match(/(\w+)\s+eq\s+([\d.]+)/);
        if (m) { filters.push({ field: m[1], op: "eq", value: m[2] }); continue; }
        // Match: Field gt/lt/ge/le Value
        m = cond.match(/(\w+)\s+(gt|lt|ge|le)\s+([\d.]+)/);
        if (m) { filters.push({ field: m[1], op: m[2], value: parseFloat(m[3]) }); continue; }
        // Match: substringof('Value', Field) eq true
        m = cond.match(/substringof\('([^']+)',\s*(\w+)\)\s+eq\s+true/);
        if (m) { filters.push({ field: m[2], op: "contains", value: m[1] }); continue; }
    }
    return filters.length > 0 ? filters : null;
}

function applyFilter(results, filters) {
    if (!filters) return results;
    return results.filter(record => {
        return filters.every(f => {
            const val = record[f.field];
            if (val === undefined) return false;
            switch (f.op) {
                case "eq": return String(val) === String(f.value);
                case "gt": return parseFloat(val) > f.value;
                case "lt": return parseFloat(val) < f.value;
                case "ge": return parseFloat(val) >= f.value;
                case "le": return parseFloat(val) <= f.value;
                case "contains": return String(val).includes(f.value);
                default: return true;
            }
        });
    });
}

function parseQueryParams(url) {
    const qIdx = url.indexOf("?");
    if (qIdx === -1) return {};
    const params = {};
    const qs = url.substring(qIdx + 1);
    for (const part of qs.split("&")) {
        const [k, ...vParts] = part.split("=");
        // Replace + with space BEFORE decodeURIComponent (URLSearchParams encodes spaces as +)
        const key = decodeURIComponent(k.replace(/\+/g, " "));
        const val = decodeURIComponent(vParts.join("=").replace(/\+/g, " "));
        params[key] = val;
    }
    return params;
}

// ── Server ───────────────────────────────────────────────────────────────────

const server = http.createServer((req, res) => {
    // Parse query params BEFORE stripping them
    const queryParams = parseQueryParams(req.url);
    // Strip base path prefix and query string for mock lookup
    const rawPath = req.url.split("?")[0].replace(/^\/odata\/sap\//, "").replace(/\/$/, "");

    console.log(`[mock] ${req.method} /${rawPath}${queryParams["$filter"] ? " $filter=" + queryParams["$filter"] : ""}`);

    // $metadata
    const metaMatch = rawPath.match(/^([^/]+)\/\$metadata$/);
    if (metaMatch) {
        const svc = metaMatch[1];
        const xml = METADATA[svc];
        if (xml) {
            res.writeHead(200, { "Content-Type": "application/xml" });
            res.end(xml);
            return;
        }
    }

    // Service root (used by sap_connect test)
    const svcRoot = rawPath.match(/^([^/]+)\/?$/);
    if (svcRoot && METADATA[svcRoot[1]]) {
        res.writeHead(200, { "Content-Type": "application/json" });
        res.end(JSON.stringify({ d: { EntitySets: [rawPath.replace(/\/$/, "")] } }));
        return;
    }

    // POST — return 201 created (echo body)
    if (req.method === "POST") {
        let body = "";
        req.on("data", chunk => { body += chunk; });
        req.on("end", () => {
            let parsed = {};
            try { parsed = JSON.parse(body); } catch (_) { }
            res.writeHead(201, { "Content-Type": "application/json" });
            res.end(JSON.stringify({ d: { ...parsed, __mock: true } }));
        });
        return;
    }

    // PATCH / PUT — return 204
    if (req.method === "PATCH" || req.method === "PUT") {
        res.writeHead(204);
        res.end();
        return;
    }

    // DELETE — return 204
    if (req.method === "DELETE") {
        res.writeHead(204);
        res.end();
        return;
    }

    // GET — look up mock data (try direct match first, then normalize named keys to positional)
    let data = MOCK[rawPath];

    if (!data) {
        // Convert named-key format A_Entity(Field='val') → A_Entity('val')
        // and A_Entity(F1='v1',F2='v2') → A_Entity('v1','v2')
        const normalized = rawPath.replace(/\(([^)]+)\)/, (_, inner) => {
            if (!inner.includes("=")) return `(${inner})`;
            const values = inner.split(",").map(kv => kv.split("=").slice(1).join("="));
            return `(${values.join(",")})`;
        });
        if (normalized !== rawPath) {
            data = MOCK[normalized];
            if (data) console.log(`[mock] normalized key: ${rawPath} → ${normalized}`);
        }
    }

    if (data) {
        // Apply $filter and $top if this is a collection response
        let responseData = data;
        if (data.d && data.d.results && Array.isArray(data.d.results)) {
            let results = data.d.results;
            // Apply $filter
            const filterStr = queryParams["$filter"];
            if (filterStr) {
                const filters = parseFilter(filterStr);
                if (filters) {
                    results = applyFilter(results, filters);
                    console.log(`[mock] $filter applied: ${results.length} of ${data.d.results.length} records match`);
                }
            }
            // Apply $top
            const top = parseInt(queryParams["$top"]);
            if (top > 0 && results.length > top) {
                results = results.slice(0, top);
            }
            // Apply $select (trim fields)
            const selectStr = queryParams["$select"];
            if (selectStr) {
                const fields = selectStr.split(",").map(f => f.trim());
                results = results.map(r => {
                    const filtered = {};
                    for (const f of fields) {
                        if (r[f] !== undefined) filtered[f] = r[f];
                    }
                    return filtered;
                });
            }
            responseData = { d: { results } };
        }
        res.writeHead(200, { "Content-Type": "application/json" });
        res.end(JSON.stringify(responseData));
        return;
    }

    // 404 fallback
    console.log(`[mock] 404 — unknown path: ${rawPath}`);
    res.writeHead(404, { "Content-Type": "application/json" });
    res.end(JSON.stringify({ error: { code: "404", message: `No mock for: ${rawPath}` } }));
});

server.listen(PORT, "127.0.0.1", () => {
    console.log(`SAP OData mock server running at http://127.0.0.1:${PORT}/odata/sap/`);
});
